import{j as a,b as t,c as l,aa as i}from"./chunks/framework.Bxf40uRC.js";const k=JSON.parse('{"title":"面试部分","description":"","frontmatter":{},"headers":[],"relativePath":"Mysql/面试题.md","filePath":"Mysql/面试题.md","lastUpdated":null}'),e={name:"Mysql/面试题.md"},o=i('<h1 id="面试部分" tabindex="-1">面试部分 <a class="header-anchor" href="#面试部分" aria-label="Permalink to &quot;面试部分&quot;">​</a></h1><h2 id="_1、如何避免索引失效" tabindex="-1">1、如何避免索引失效？ <a class="header-anchor" href="#_1、如何避免索引失效" aria-label="Permalink to &quot;1、如何避免索引失效？&quot;">​</a></h2><ol><li>对索引使用左匹配或者左右模糊匹配</li><li>对索引使用函数</li><li>对索引进行表达式计算</li><li>对索引隐式类型转换</li><li>联合索引非最左匹配</li><li><u>where</u>子句中的OR</li></ol><h2 id="_2、mysql使用-like-x-索引一定会失效吗" tabindex="-1">2、Mysql使用 &quot;like %x&quot;，索引一定会失效吗？ <a class="header-anchor" href="#_2、mysql使用-like-x-索引一定会失效吗" aria-label="Permalink to &quot;2、Mysql使用 &quot;like %x&quot;，索引一定会失效吗？&quot;">​</a></h2><p><img src="https://s2.loli.net/2024/01/06/LPOu3GJBoxiX9ew.png" alt="图片"></p><h3 id="题目一" tabindex="-1">题目一 <a class="header-anchor" href="#题目一" aria-label="Permalink to &quot;题目一&quot;">​</a></h3><ol><li>因为name是二级索引，所以查询的时候，会触发索引扫描</li><li>右匹配，仍然会走索引扫描</li><li>左匹配，索引失效</li><li>左右匹配，索引失效</li></ol><h3 id="题目二" tabindex="-1">题目二 <a class="header-anchor" href="#题目二" aria-label="Permalink to &quot;题目二&quot;">​</a></h3><ol><li>走索引扫描</li><li>索引扫描，但<strong>覆盖索引</strong></li><li>索引扫描，但<strong>覆盖索引</strong></li><li>索引扫描，但<strong>覆盖索引</strong></li></ol><p>为什么会出现这种情况呢？</p><p>首先这张表的字段没有非索引字段，所以select*等价于select id，name；然后这个查询的数据都在二级索引的B+树中，<strong>因为二级索引B+树的叶子节点包含索引值和主键值，所以查二级索引的B+树就能够查到全部的结果了，这个就是覆盖索引。</strong></p><h4 id="为什么选择全扫描二级索引树-而不扫描聚簇索引树呢" tabindex="-1">为什么选择全扫描二级索引树，而不扫描聚簇索引树呢？ <a class="header-anchor" href="#为什么选择全扫描二级索引树-而不扫描聚簇索引树呢" aria-label="Permalink to &quot;为什么选择全扫描二级索引树，而不扫描聚簇索引树呢？&quot;">​</a></h4><p>因为二级索引树记录的东西很少，只有[索引列+主键值]，而聚簇索引记录的东西会更多，比如聚簇索引中的叶子节点则记录了主键值、事务id、用于事务的MVCC的回滚指针以及所有的剩余列。</p><p>再加上，这个select*不用执行回表操作。</p><p>所以MySql优化器认为直接遍历二级索引树要比遍历聚簇索引树的成本小的多，因此MySql选择了[全扫描二级索引树]的方式查询数据；</p><h2 id="_3、count-和-count-1-有什么区别-哪个性能最好" tabindex="-1">3、Count(*) 和 Count(1)有什么区别？哪个性能最好? <a class="header-anchor" href="#_3、count-和-count-1-有什么区别-哪个性能最好" aria-label="Permalink to &quot;3、Count(*) 和 Count(1)有什么区别？哪个性能最好?&quot;">​</a></h2><p><img src="https://s2.loli.net/2024/01/06/lYdxuUnXRFL2hZe.png" alt="图片"></p><h3 id="哪种count性能最好" tabindex="-1">哪种count性能最好？ <a class="header-anchor" href="#哪种count性能最好" aria-label="Permalink to &quot;哪种count性能最好？&quot;">​</a></h3><p><img src="https://cdn.xiaolincoding.com//mysql/other/af711033aa3423330d3a4bc6baeb9532.png" alt="图片"></p><h3 id="count-是什么" tabindex="-1">count()是什么？ <a class="header-anchor" href="#count-是什么" aria-label="Permalink to &quot;count()是什么？&quot;">​</a></h3><p>count()是一个聚合函数，函数的参数不仅可以是字段名，也可以是其他任意表达式，该函数的作用是统计符合查询条件的记录中，函数指定的参数不为null的记录有多少个。</p><p>假设count()函数参数是字段名name，意思就是统计该表中所有name不为空的记录有多少个。</p><p>再来假设 count() 函数的参数是数字 1 这个表达式，如下：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> count</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> t_order;</span></span></code></pre></div><p>这条语句是统计「 t_order 表中，1 这个表达式不为 NULL 的记录」有多少个。</p><p>1 这个表达式就是单纯数字，它永远都不是 NULL，所以上面这条语句，其实是在统计 t_order 表中有多少个记录</p><ol><li>count(主键字段)会优先选择二级索引然后再选择聚簇索引(主键索引)，前者维护的信息更少一点，但都是通过遍历得到最后的结果；</li><li>count(1)，如果只有聚簇索引，那么就遍历聚簇索引，将读取到的记录返回给server层，但是server层不会读取记录，读到一条count就+1，所以比count(主键)快；</li><li>count(*)，等于count(0)和count(1)一致；但是MySql会对count(*) 和count(1)有优化，如果有多个二级索引时，优化器会使用key_len最小的二级索引进行扫描；只有当没有二级索引的时候，才会使用主键索引进行统计；</li><li>count(字段)，使用全表扫描；</li></ol><h2 id="_4、为什么要通过遍历的方式来计数" tabindex="-1">4、为什么要通过遍历的方式来计数？ <a class="header-anchor" href="#_4、为什么要通过遍历的方式来计数" aria-label="Permalink to &quot;4、为什么要通过遍历的方式来计数？&quot;">​</a></h2><p>因为InnoDB存储引擎是支持事务的，同一时刻多个查询，由于多版本并发控制(MVCC)的原因，InnoDB表应该返回多少行也是不确定的；</p><h2 id="_5、如何优化count" tabindex="-1">5、如何优化Count(*) <a class="header-anchor" href="#_5、如何优化count" aria-label="Permalink to &quot;5、如何优化Count(*)&quot;">​</a></h2><ol><li>采用近似值，使用explain命令进行估算即可；</li><li>采用单独的表来进行记录，不过就需要额外进行单独的维护；</li></ol>',31),n=[o];function s(r,h,c,u,d,p){return t(),l("div",null,n)}const q=a(e,[["render",s]]);export{k as __pageData,q as default};
